void* pool_alloc(MemoryPool* pool) {
// 1. Immutable check (Safe, no lock)
if (!pool) return NULL;

pre.code:
// 2. Acquire Mutex (Critical Section Start)
pthread_mutex_lock(&pool->mutex); 

// 3. Access Mutable Shared State
if (pool->free_list_head == NULL) {
    if (!grow_pool(pool)) {
        pthread_mutex_unlock(&pool->mutex);
        return NULL;
    }
}

void* block = pool->free_list_head;
pool->free_list_head = *(void**)block;
pool->allocated++;

// 4. Release Mutex (Critical Section End)
pthread_mutex_unlock(&pool->mutex);

return block;
